            { word: "कुर्वन्", transliteration: "kurvan", meaning: "performing" },
            { word: "न आप्नोति", transliteration: "na āpnoti", meaning: "does not incur" },
            { word: "किल्बिषम्", transliteration: "kilbiṣam", meaning: "sin" }
